import{_ as n,o as a,c as i,ag as e}from"./chunks/framework.DGzMGr_a.js";const k=JSON.parse('{"title":"TypeScript 编译原理与性能优化","description":"","frontmatter":{"title":"TypeScript 编译原理与性能优化","difficulty":"hard","tags":["TypeScript","编译原理","tsc","性能优化","esbuild","swc"],"estimate":25},"headers":[],"relativePath":"domains/typescript/qa/qa-20-compiler-performance.md","filePath":"domains/typescript/qa/qa-20-compiler-performance.md","lastUpdated":1783504823000}'),t={name:"domains/typescript/qa/qa-20-compiler-performance.md"};function p(l,s,r,o,d,c){return a(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="问答-20-高级-typescript-编译原理与性能优化" tabindex="-1">问答 20（高级）：TypeScript 编译原理与性能优化 <a class="header-anchor" href="#问答-20-高级-typescript-编译原理与性能优化" aria-label="Permalink to &quot;问答 20（高级）：TypeScript 编译原理与性能优化&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请介绍 TypeScript 的编译流程（Parse → Bind → Check → Emit），以及常见的编译性能优化手段：增量编译（<code>--incremental</code>）、项目引用（Project References）、<code>skipLibCheck</code>、<code>isolatedModules</code>。再说说 esbuild / swc 为什么比 <code>tsc</code> 快，以及它们和 <code>tsc</code> 的区别。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>TypeScript 编译器（tsc）的整体架构</strong></p><p>TS 编译器是用 TS 自己写的（自举），编译过程分四大步：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源码 → Parse → Bind → Check → Emit → JS 代码</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每一步都有明确的职责，而且<strong>类型检查（Check）和代码生成（Emit）是解耦的</strong>——这就是为什么可以用 esbuild / swc 来做代码生成，而把类型检查留给 <code>tsc --noEmit</code>。</p><hr><p><strong>阶段 1：Parse（解析）</strong></p><p>把源码字符串解析成 <strong>AST</strong>（抽象语法树）。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源代码 → 词法分析（Scanner）→ Token 流 → 语法分析（Parser）→ AST</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>Scanner</strong>：逐字符扫描，把字符串切成一个个 token（关键字、标识符、运算符等）</li><li><strong>Parser</strong>：根据语法规则把 token 组装成 AST</li></ul><p>AST 是一棵表示代码结构的树，每个节点代表一个语法结构（<code>FunctionDeclaration</code>、<code>IfStatement</code>、<code>CallExpression</code> 等）。</p><p>这个阶段和类型没有关系——只关心&quot;代码写对了没有&quot;，不关心&quot;类型对不对&quot;。</p><hr><p><strong>阶段 2：Bind（绑定）</strong></p><p>把 AST 上的每个标识符（变量名、函数名等）和它的**声明（Symbol）**关联起来，建立作用域链。</p><p>比如：</p><ul><li><code>const x = 1;</code> 声明了一个 Symbol <code>x</code></li><li><code>console.log(x);</code> 中的 <code>x</code> 要绑定到上面那个 Symbol</li></ul><p>Bind 阶段的产物是：</p><ul><li><strong>Symbols</strong>：每个声明对应一个 Symbol，包含类型信息、声明位置等</li><li><strong>作用域树</strong>：每个作用域有哪些声明，父子作用域关系</li></ul><p>为什么需要 Bind 阶段？因为光有 AST 不够——你不知道某个 <code>x</code> 到底指的是哪个 <code>x</code>（是外面的？还是当前函数里的？）。Bind 就是把&quot;引用&quot;和&quot;定义&quot;连起来。</p><hr><p><strong>阶段 3：Check（类型检查）——最耗时的一步</strong></p><p>遍历 AST，逐个节点检查类型是否正确。这是 TS 的核心，也是最慢的一步。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>对每个节点：</span></span>
<span class="line"><span>  1. 推断它的类型</span></span>
<span class="line"><span>  2. 检查类型是否符合预期</span></span>
<span class="line"><span>  3. 如果是表达式，检查运算合法性</span></span>
<span class="line"><span>  4. 如果是函数调用，检查参数类型、返回值类型</span></span>
<span class="line"><span>  ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>类型检查为什么慢？因为：</p><ul><li><strong>类型推导</strong>：泛型、条件类型、映射类型、模板字面量... 越复杂的类型，推导越费时间</li><li><strong>跨文件分析</strong>：模块之间的类型依赖，需要先加载所有依赖的 <code>.d.ts</code></li><li><strong>结构化比较</strong>：TS 是结构化类型系统，判断两个类型是否相等可能要递归比较整个结构</li><li><strong>缓存很难做</strong>：一个文件的类型变了，可能影响很多其他文件</li></ul><hr><p><strong>阶段 4：Emit（发射 / 代码生成）</strong></p><p>把 AST 转换成 JavaScript 代码（以及 <code>.d.ts</code> 文件、sourcemap 等）。</p><p>Emit 阶段其实<strong>不做类型检查</strong>——它只是把 TS 语法（类型注解、接口、泛型等）&quot;抹掉&quot;，剩下的就是 JS。</p><p>这就是为什么：</p><ul><li><code>tsc --noEmit</code> 只做类型检查，不生成 JS</li><li>esbuild / swc 可以&quot;跳过类型检查&quot;直接转译——因为转译只需要 Parse + Emit，不需要 Check</li></ul><hr><p><strong>为什么类型检查和代码生成要解耦？</strong></p><p>这个设计非常重要：</p><ol><li><strong>性能优化空间大</strong>：转译可以用更快的工具（esbuild/swc），类型检查交给专门的进程</li><li><strong>开发体验好</strong>：开发时快速刷新（靠快速转译），类型检查在后台跑</li><li><strong>构建流水线灵活</strong>：可以并行做类型检查和代码打包</li></ol><p>现代前端工程的常见做法就是：</p><ul><li><strong>开发时</strong>：Vite / esbuild 做快速转译（毫秒级），TS 类型检查在 IDE 或单独进程里跑</li><li><strong>构建时</strong>：先 <code>tsc --noEmit</code> 做类型检查，通过了再用 esbuild/rollup 打包</li></ul><hr><p><strong>编译性能优化手段</strong></p><h3 id="_1-增量编译-incremental" tabindex="-1">1. 增量编译（<code>--incremental</code>） <a class="header-anchor" href="#_1-增量编译-incremental" aria-label="Permalink to &quot;1. 增量编译（\`--incremental\`）&quot;">​</a></h3><p>TS 3.4 引入。第一次编译后生成一个 <code>.tsbuildinfo</code> 文件，记录了每个文件的哈希和依赖关系。下次编译时，只重新检查<strong>变化了的文件</strong>和<strong>受影响的文件</strong>。</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;compilerOptions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;incremental&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;tsBuildInfoFile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;./.tsbuildinfo&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>效果</strong>：二次编译速度可以快好几倍，特别是项目大的时候。</p><p><strong>适用场景</strong>：日常开发、CI 的缓存构建。</p><h3 id="_2-项目引用-project-references" tabindex="-1">2. 项目引用（Project References） <a class="header-anchor" href="#_2-项目引用-project-references" aria-label="Permalink to &quot;2. 项目引用（Project References）&quot;">​</a></h3><p>TS 3.0 引入。把一个大项目拆成多个小项目（每个有自己的 <code>tsconfig.json</code>），互相之间有依赖关系。</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// tsconfig.json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;references&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;./core&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;./app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>好处：</p><ul><li><strong>模块化</strong>：每个子项目独立编译，边界清晰</li><li><strong>更快的构建</strong>：改了 app 不用重新检查 core</li><li><strong>更好的隔离</strong>：避免内部类型被意外引用</li></ul><p><strong>适用场景</strong>：大型 monorepo、多包项目。</p><h3 id="_3-skiplibcheck" tabindex="-1">3. <code>skipLibCheck</code> <a class="header-anchor" href="#_3-skiplibcheck" aria-label="Permalink to &quot;3. \`skipLibCheck\`&quot;">​</a></h3><p>跳过对 <code>.d.ts</code> 声明文件的类型检查。</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;compilerOptions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;skipLibCheck&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>为什么可以跳过？因为：</p><ul><li><code>.d.ts</code> 文件一般是第三方库的，质量有保障</li><li>不同库的 <code>.d.ts</code> 之间可能有冲突（版本不一致），全检查会报很多无关的错</li><li>我们只关心自己写的代码的类型检查</li></ul><p><strong>效果</strong>：编译时间大幅减少（特别是依赖很多的时候）。</p><p><strong>注意</strong>：<code>skipLibCheck</code> 不是完全忽略 <code>.d.ts</code>——TS 还是会用这些类型来做你代码的检查，只是不检查声明文件本身的内部一致性。</p><h3 id="_4-isolatedmodules" tabindex="-1">4. <code>isolatedModules</code> <a class="header-anchor" href="#_4-isolatedmodules" aria-label="Permalink to &quot;4. \`isolatedModules\`&quot;">​</a></h3><p>确保每个文件都可以被单独转译（不需要其他文件的类型信息）。</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;compilerOptions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;isolatedModules&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>为什么需要这个？因为像 esbuild / swc / Babel 这些单文件转译器，它们逐个文件处理，不做跨文件分析。如果你的代码依赖了&quot;需要跨文件才能知道的信息&quot;（比如 <code>const enum</code>），单文件转译就处理不了。</p><p>开启 <code>isolatedModules</code> 后，TS 会帮你检查：</p><ul><li>不能用 <code>const enum</code>（跨文件枚举值会被内联，单文件转译做不到）</li><li>不能 re-export 类型（要加 <code>import type</code> / <code>export type</code>）</li><li>不能有隐式类型依赖</li></ul><p><strong>适用场景</strong>：用 esbuild / swc / Babel 做转译的项目。</p><hr><p><strong>esbuild / swc 为什么比 tsc 快？</strong></p><table tabindex="0"><thead><tr><th>对比维度</th><th>tsc</th><th>esbuild</th><th>swc</th></tr></thead><tbody><tr><td>语言</td><td>TypeScript（JS 引擎运行）</td><td>Go（原生二进制）</td><td>Rust（原生二进制）</td></tr><tr><td>做类型检查吗</td><td>✅ 做</td><td>❌ 不做</td><td>❌ 不做</td></tr><tr><td>并行度</td><td>单线程（主要）</td><td>高度并行</td><td>高度并行</td></tr><tr><td>架构</td><td>全流程（Parse→Bind→Check→Emit）</td><td>只做转译（Parse→Emit）</td><td>只做转译（Parse→Emit）</td></tr></tbody></table><p><strong>快的核心原因有三个：</strong></p><ol><li><strong>语言优势</strong>：Go / Rust 是编译型语言，原生运行，比 JS 快很多。而且可以充分利用多核。</li><li><strong>不做类型检查</strong>：最耗时的 Check 阶段完全跳过，只做语法转译。</li><li><strong>高度优化</strong>：esbuild/swc 都做了大量底层优化（内存布局、缓存、并行算法等）。</li></ol><p><strong>它们和 tsc 的区别</strong>：</p><table tabindex="0"><thead><tr><th>功能</th><th>tsc</th><th>esbuild</th><th>swc</th></tr></thead><tbody><tr><td>类型检查</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>转译 TS→JS</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>生成 <code>.d.ts</code></td><td>✅</td><td>❌</td><td>❌（需要额外插件）</td></tr><tr><td>增量编译</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>打包 bundle</td><td>❌（只编译文件）</td><td>✅</td><td>❌（swcpack 在做）</td></tr><tr><td>速度</td><td>慢</td><td>极快</td><td>极快</td></tr></tbody></table><p><strong>现代项目的典型组合</strong>：</p><ul><li><strong>开发阶段</strong>：Vite + esbuild / swc 做快速 HMR，类型检查交给 IDE 或 <code>tsc --noEmit</code></li><li><strong>构建阶段</strong>：先用 <code>tsc --noEmit</code> 做类型检查，通过了再用 esbuild / rollup / webpack 打包</li><li><strong>生成类型声明</strong>：用 <code>tsc --declaration --emitDeclarationOnly</code> 单独生成 <code>.d.ts</code></li></ul><hr><p><strong>一张图总结性能优化手段</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目大、编译慢？</span></span>
<span class="line"><span>├── 代码层面</span></span>
<span class="line"><span>│   ├── 减少复杂类型体操（特别是深递归）</span></span>
<span class="line"><span>│   ├── 避免 any 滥用导致的隐式类型推导</span></span>
<span class="line"><span>│   └── 合理拆分模块，减少循环依赖</span></span>
<span class="line"><span>├── 配置层面</span></span>
<span class="line"><span>│   ├── incremental + tsBuildInfoFile</span></span>
<span class="line"><span>│   ├── skipLibCheck: true</span></span>
<span class="line"><span>│   ├── projectReferences（monorepo）</span></span>
<span class="line"><span>│   └── strict 按需开启（全开更慢但更安全）</span></span>
<span class="line"><span>└── 工具层面</span></span>
<span class="line"><span>    ├── 转译用 esbuild / swc 替代 tsc</span></span>
<span class="line"><span>    ├── 类型检查用 tsc --noEmit 单独跑</span></span>
<span class="line"><span>    └── CI 里缓存 .tsbuildinfo 和 node_modules</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="追问-1-ts-编译器的-类型检查-具体慢在哪里-为什么类型系统会有性能问题" tabindex="-1">追问 1：TS 编译器的&quot;类型检查&quot;具体慢在哪里？为什么类型系统会有性能问题？ <a class="header-anchor" href="#追问-1-ts-编译器的-类型检查-具体慢在哪里-为什么类型系统会有性能问题" aria-label="Permalink to &quot;追问 1：TS 编译器的&quot;类型检查&quot;具体慢在哪里？为什么类型系统会有性能问题？&quot;">​</a></h2><h3 id="答" tabindex="-1">答 <a class="header-anchor" href="#答" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>TS 类型检查慢，根源在于它的类型系统太强大了——TS 的类型系统是<strong>图灵完备</strong>的，理论上可以做任何计算。实际中的性能瓶颈主要在这几个地方：</p><p><strong>1. 复杂类型的递归展开</strong></p><p>条件类型、映射类型、模板字面量类型组合起来，会产生大量的类型展开和比较。比如一个嵌套 10 层的 <code>DeepPartial&lt;T&gt;</code>，每次使用都要递归计算类型。</p><p><strong>2. 结构化类型比较</strong></p><p>TS 是<strong>结构化类型系统</strong>（nominal 是名义类型系统）——判断两个类型是否相等，要递归比较它们的&quot;形状&quot;。类型越复杂，比较成本越高。</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> A</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">z</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } } }</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> B</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">z</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } } }</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 比较 A 和 B 是否相等？要递归比较到最内层</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>3. 泛型实例化</strong></p><p>每次使用泛型类型，TS 都要把类型参数代入，实例化出具体类型。泛型用得越多，实例化开销越大。</p><p><strong>4. 联合类型的组合爆炸</strong></p><p>模板字面量类型 + 联合类型会产生笛卡尔积，联合成员太多时 TS 会直接报 &quot;Type produces a union type that is too complex to represent&quot;。</p><p><strong>5. 增量检查的粒度问题</strong></p><p>虽然有 <code>--incremental</code>，但类型系统的依赖关系很难精确追踪——一个文件的小改动，可能导致很多依赖它的文件都要重新检查。</p><p><strong>怎么优化类型层面的性能？</strong></p><ul><li>避免过深的递归类型（超过 10 层就要小心）</li><li>用 <code>interface</code> 代替复杂的交叉类型（interface 的比较更高效）</li><li>大项目用项目引用拆分</li><li>对第三方库开 <code>skipLibCheck</code></li></ul><p>TS 团队也在不断优化类型检查器的性能（比如更聪明的缓存、延迟计算），但根本上——类型系统越强大，检查就越慢，这是 tradeoff。</p><h2 id="追问-2-tsc-noemit-和-tsc-的区别是什么-实际项目中怎么搭配用" tabindex="-1">追问 2：<code>tsc --noEmit</code> 和 <code>tsc</code> 的区别是什么？实际项目中怎么搭配用？ <a class="header-anchor" href="#追问-2-tsc-noemit-和-tsc-的区别是什么-实际项目中怎么搭配用" aria-label="Permalink to &quot;追问 2：\`tsc --noEmit\` 和 \`tsc\` 的区别是什么？实际项目中怎么搭配用？&quot;">​</a></h2><h3 id="答-1" tabindex="-1">答 <a class="header-anchor" href="#答-1" aria-label="Permalink to &quot;答&quot;">​</a></h3><ul><li><code>tsc</code>：做完整的类型检查 + 生成 JS 文件（可能还生成 <code>.d.ts</code>、sourcemap）</li><li><code>tsc --noEmit</code>：<strong>只做类型检查</strong>，不输出任何文件</li></ul><p><strong>为什么需要 <code>--noEmit</code>？</strong></p><p>因为现代项目里，代码生成（转译 + 打包）往往不用 tsc，而是用更快的 esbuild / swc / webpack / rollup。类型检查是独立的一步。</p><p><strong>典型项目配置</strong>：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// package.json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;scripts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;dev&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vite&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 开发：vite + esbuild 快速刷新</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npm run typecheck &amp;&amp; vite build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 构建：先类型检查，再打包</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;typecheck&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tsc --noEmit&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // 单独跑类型检查</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>分工是这样的</strong>：</p><table tabindex="0"><thead><tr><th>工具</th><th>负责什么</th><th>特点</th></tr></thead><tbody><tr><td>esbuild / swc / vite</td><td>转译 TS→JS、打包、HMR</td><td>快，但不检查类型</td></tr><tr><td>tsc --noEmit</td><td>类型检查</td><td>慢，但能发现类型错误</td></tr><tr><td>tsc --declaration</td><td>生成 <code>.d.ts</code> 类型声明</td><td>库项目才需要</td></tr></tbody></table><p><strong>为什么不直接用 tsc 做所有事？</strong></p><ul><li>开发时 HMR 需要毫秒级响应，tsc 太慢了</li><li>打包（tree-shaking、代码分割等）不是 tsc 的强项</li><li>但类型检查只有 tsc 做得最完整、最准确</li></ul><p>这种&quot;转译和类型检查分离&quot;的架构，是现代 TS 项目的标准实践。</p><h2 id="追问-3-项目引用-project-references-和-monorepo-工具-比如-turborepo-nx-是什么关系" tabindex="-1">追问 3：项目引用（Project References）和 monorepo 工具（比如 Turborepo / Nx）是什么关系？ <a class="header-anchor" href="#追问-3-项目引用-project-references-和-monorepo-工具-比如-turborepo-nx-是什么关系" aria-label="Permalink to &quot;追问 3：项目引用（Project References）和 monorepo 工具（比如 Turborepo / Nx）是什么关系？&quot;">​</a></h2><h3 id="答-2" tabindex="-1">答 <a class="header-anchor" href="#答-2" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>它们是不同层面的东西，但可以配合使用：</p><ul><li><strong>TS 项目引用</strong>：是<strong>类型层面</strong>的模块化——告诉 TS 编译器&quot;这些子项目之间的依赖关系&quot;，让类型检查更快、更有边界。</li><li><strong>Turborepo / Nx</strong>：是<strong>任务编排层面</strong>的 monorepo 工具——管的是构建、测试、lint 等任务的依赖关系、缓存、并行执行。</li></ul><p><strong>它们怎么配合？</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Monorepo 根目录</span></span>
<span class="line"><span>├── tsconfig.json          // 根配置，包含 references</span></span>
<span class="line"><span>├── packages/</span></span>
<span class="line"><span>│   ├── core/              // 子项目 A</span></span>
<span class="line"><span>│   │   └── tsconfig.json  // 有 composite: true</span></span>
<span class="line"><span>│   └── app/               // 子项目 B</span></span>
<span class="line"><span>│       └── tsconfig.json  // 有 references: [{ path: &quot;../core&quot; }]</span></span>
<span class="line"><span>└── turbo.json             // Turborepo 配置</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li><strong>TS 层面</strong>：<code>app</code> 依赖 <code>core</code>，TS 知道先编译 <code>core</code> 再编译 <code>app</code>，改了 <code>app</code> 不用重新检查 <code>core</code></li><li><strong>任务层面</strong>：Turborepo 知道 <code>app:build</code> 依赖 <code>core:build</code>，会按正确顺序执行，还能缓存每个包的构建结果</li></ul><p><strong>为什么两者都需要？</strong></p><p>只用 Turborepo 不用项目引用：</p><ul><li>每个包的 <code>tsc</code> 是独立跑的，不知道其他包的类型变化</li><li>可能出现&quot;包 A 改了类型但包 B 没重新检查&quot;的问题</li><li>IDE 里的类型提示也可能不连贯</li></ul><p>只用项目引用不用 Turborepo：</p><ul><li>类型检查层面优化了，但构建、测试等任务没有统一编排</li><li>缓存、并行执行、远程缓存等能力没有</li></ul><p><strong>最佳实践</strong>：</p><ul><li>大型 monorepo → 两者都用，各司其职</li><li>小型 monorepo → 用项目引用可能就够了，不需要上重量级的 Turborepo/Nx</li></ul><p>简单说：<strong>项目引用管&quot;类型检查的模块化&quot;，Turborepo 管&quot;任务执行的模块化&quot;</strong>，两者互补，不冲突。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/typescript/RESOURCES">TypeScript 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://github.com/microsoft/TypeScript/wiki/Performance" target="_blank" rel="noreferrer">TypeScript Wiki: Performance</a>：大型项目编译性能实践、<code>incremental</code> 与项目引用。</li><li><a href="https://www.typescriptlang.org/tsconfig#references" target="_blank" rel="noreferrer">TSConfig: Project References</a>：项目引用的配置方式与增量类型检查。</li><li><a href="https://www.typescriptlang.org/tsconfig#skipLibCheck" target="_blank" rel="noreferrer">TSConfig: skipLibCheck</a>：<code>skipLibCheck</code>/<code>isolatedModules</code> 等加速选项的官方说明。</li></ul>`,127)])])}const u=n(t,[["render",p]]);export{k as __pageData,u as default};
